            if op == 'r':
                read_sets[i].add(key)
            else:
                write_sets[i].add(key)
        txn_lengths[i] = length

    conflict_matrix = [[False] * n for _ in range(n)]
    for i in range(n):
        for j in range(i + 1, n):
            if (write_sets[i] & write_sets[j]) or \
               (write_sets[i] & read_sets[j]) or \
               (read_sets[i] & write_sets[j]):
                conflict_matrix[i][j] = True
                conflict_matrix[j][i] = True

    conflict_degree = [0.0] * n
    for i in range(n):
        for j in range(n):
            if i != j and conflict_matrix[i][j]:
                ww = len(write_sets[i] & write_sets[j])
                rw = len(read_sets[i] & write_sets[j])
                wr = len(write_sets[i] & read_sets[j])
                conflict_degree[i] += ww * 2.0 + rw * 1.0 + wr * 1.0

    scores = []
    for i in range(n):
        score = (txn_lengths[i] * 0.1) + (conflict_degree[i] * 1.0)
        scores.append((score, i))
    scores.sort(reverse=True)
    base_order = [i for _, i in scores]

    schedule = []
    for txn in base_order:
        if not schedule:
            schedule.append(txn)
            continue

        candidate_pos = {0, len(schedule)}
        for idx, other in enumerate(schedule):
            if conflict_matrix[txn][other]:
                for p in range(max(0, idx - 1), min(len(schedule) + 1, idx + 2)):
                    candidate_pos.add(p)

        best_pos = 0
        min_cost = float('inf')
        for pos in sorted(list(candidate_pos)):
            test_seq = schedule[:pos] + [txn] + schedule[pos:]
            cost = workload.get_opt_seq_cost(test_seq)
            if cost < min_cost:
                min_cost = cost
                best_pos = pos

        schedule.insert(best_pos, txn)

    best_seq = schedule[:]
    best_cost = workload.get_opt_seq_cost(best_seq)

    conflict_mask = [0] * n
    for i in range(n):
        mask = 0
        for j in range(n):
            if conflict_matrix[i][j]:
                mask |= (1 << j)
        conflict_mask[i] = mask

    improved = True
    while improved:
        improved = False
        for i in range(n - 1):
            u, v = best_seq[i], best_seq[i+1]
            if conflict_matrix[u][v]:
                test_seq = best_seq[:]
                test_seq[i], test_seq[i+1] = test_seq[i+1], test_seq[i]
                test_cost = workload.get_opt_seq_cost(test_seq)
                if test_cost < best_cost:
                    best_seq = test_seq
                    best_cost = test_cost
                    improved = True
                    break

    for _ in range(200):
        i = random.randint(0, n-1)
        j = random.randint(max(0, i-3), min(n-1, i+3))
        if i == j:
            continue
        test_seq = best_seq[:]
        idx_i = test_seq.index(i)
        idx_j = test_seq.index(j)
