    key_conflicts = defaultdict(set)

    for i in range(n):
        for key in read_sets[i]:
            key_conflicts[key].add(i)
        for key in write_sets[i]:
            key_conflicts[key].add(i)

    for i in range(n):
        for j in range(n):
            if i == j:
                continue
            ww = len(write_sets[i] & write_sets[j])
            rw = len(read_sets[i] & write_sets[j])
            wr = len(write_sets[i] & read_sets[j])
            conflict_matrix[i][j] = ww + rw + wr

    total_conflicts = [sum(conflict_matrix[i]) for i in range(n)]

    def get_makespan(seq):
        return workload.get_opt_seq_cost(seq)

    def build_initial():
        candidates = sorted(range(n), key=lambda x: (total_conflicts[x], lengths[x], len(write_sets[x])), reverse=True)
        seq = []
        for txn in candidates:
            best_pos = len(seq)
            best_cost = float('inf')

            positions = {0, len(seq)}
            if seq:
                positions.add(min(5, len(seq)))
                positions.add(max(0, len(seq)-5))

            conflict_keys = write_sets[txn] | read_sets[txn]
            for key in conflict_keys:
                for other_txn in key_conflicts[key]:
                    if other_txn in seq:
                        pos = seq.index(other_txn)
                        positions.add(max(0, pos-2))
                        positions.add(pos)
                        positions.add(min(len(seq), pos+1))

            for pos in sorted(list(positions)):
                if pos > len(seq):
                    continue
                test_seq = seq[:pos] + [txn] + seq[pos:]
                cost = get_makespan(test_seq)
                if cost < best_cost:
                    best_cost = cost
                    best_pos = pos
                if cost > best_cost * 1.1 and len(seq) > 10:
                    break

            seq.insert(best_pos, txn)
        return seq

    best_seq = build_initial()
    best_cost = get_makespan(best_seq)
    current_seq = list(best_seq)
    current_cost = best_cost

    max_iter = 60000
    temp = 70.0
    cooling_rate = 0.9992
    tabu_set = set()
    tabu_size = 250

    for it in range(max_iter):
