                del new_seq[start:start+size]
                insert_pos = random.randint(0, len(new_seq))
                new_seq[insert_pos:insert_pos] = block

        seq_hash = tuple(new_seq)
        if seq_hash in tabu_set:
            continue

        new_cost = get_makespan(new_seq)
        delta = new_cost - current_cost

        if delta < 0 or random.random() < math.exp(-delta / (temp + 1e-10)):
            current_seq = new_seq
            current_cost = new_cost
            tabu_set.add(seq_hash)
            if len(tabu_set) > tabu_size:
                tabu_set.pop()

            if new_cost < best_cost:
                best_seq = new_seq[:]
                best_cost = new_cost

