                    if other_txn != txn and other_txn in partial:
                        pos = partial.index(other_txn)
                        positions.add(max(0, pos-3))
                        positions.add(max(0, pos-2))
                        positions.add(max(0, pos-1))
                        positions.add(pos)
                        positions.add(min(len(partial), pos+1))
                        positions.add(min(len(partial), pos+2))
                        positions.add(min(len(partial), pos+3))

            if len(positions) < 5:
                positions.update(range(0, len(partial)+1, max(1, len(partial)//6)))

