from collections import defaultdict
import time

def get_best_schedule(workload) -> tuple[int, list[int]]:
    n = workload.num_txns
    if n == 0:
        return 0, []

    start_time = time.time()
    max_runtime = 2.8

    txns = workload.txns

    write_sets = [set() for _ in range(n)]
    read_sets = [set() for _ in range(n)]
    txn_lengths = [0] * n
    key_writers = defaultdict(list)
    key_readers = defaultdict(list)

    for i in range(n):
        length = 0
        for op_type, key, _, l in txns[i]:
            length = l
            if op_type == 'r':
                read_sets[i].add(key)
                key_readers[key].append(i)
            else:
                write_sets[i].add(key)
                key_writers[key].append(i)
        txn_lengths[i] = length

    conflict_weight = [0] * n
    conflict_neighbors = [set() for _ in range(n)]
    all_keys = set(key_writers.keys()) | set(key_readers.keys())

    for key in all_keys:
        writers = key_writers[key]
        readers = key_readers[key]

        for i in range(len(writers)):
            for j in range(i + 1, len(writers)):
                u, v = writers[i], writers[j]
                conflict_weight[u] += 3
                conflict_weight[v] += 3
                conflict_neighbors[u].add(v)
                conflict_neighbors[v].add(u)

        for w in writers:
            for r in readers:
                conflict_weight[w] += 2
                conflict_weight[r] += 1
                conflict_neighbors[w].add(r)
                conflict_neighbors[r].add(w)

    def generate_initial_schedule():
        write_counts = [len(write_sets[i]) for i in range(n)]
        candidates = sorted(range(n), key=lambda i: (
            -write_counts[i] * 2.0 - conflict_weight[i] * 1.5 - txn_lengths[i] * 1.0 + random.random() * 0.3
        ))

        schedule = []
        for txn in candidates:
            if not schedule:
                schedule.append(txn)
                continue

            best_pos = 0
            best_cost = float('inf')

            positions = {0, len(schedule)}
            for idx, existing in enumerate(schedule):
                if existing in conflict_neighbors[txn]:
                    for p in range(max(0, idx-1), min(len(schedule)+1, idx+2)):
                        positions.add(p)

            if len(positions) < 4:
                positions.update(range(0, len(schedule)+1, max(1, len(schedule)//5)))

            for pos in sorted(list(positions)):
                test_seq = schedule[:pos] + [txn] + schedule[pos:]
                cost = workload.get_opt_seq_cost(test_seq)
                if cost < best_cost:
                    best_cost = cost
                    best_pos = pos
                    if cost < best_cost * 0.95:
                        break

            schedule.insert(best_pos, txn)

        return schedule

    def simulated_annealing(initial_seq):
        current_seq = initial_seq[:]
        current_cost = workload.get_opt_seq_cost(current_seq)
        best_seq = current_seq[:]
        best_cost = current_cost

        iterations = 30000
        temp = 150.0
        cooling = 0.9995

        for i in range(iterations):
            if time.time() - start_time > max_runtime:
                break

            new_seq = current_seq[:]

            r = random.random()
            if r < 0.4:
                a, b = random.sample(range(n), 2)
                new_seq[a], new_seq[b] = new_seq[b], new_seq[a]
            elif r < 0.7:
                src = random.randrange(n)
                dst = random.randrange(n)
                if src != dst:
                    val = new_seq.pop(src)
                    new_seq.insert(dst, val)
            elif r < 0.9:
                if n > 4:
                    size = random.randint(3, 6)
                    start = random.randrange(n - size + 1)
                    new_seq[start:start+size] = reversed(new_seq[start:start+size])
            else:
                if n > 10:
                    s = sorted(random.sample(range(n), 2))
                    new_seq[s[0]:s[1]+1] = reversed(new_seq[s[0]:s[1]+1])

            new_cost = workload.get_opt_seq_cost(new_seq)
            delta = new_cost - current_cost

            if delta < 0 or math.exp(-delta / temp) > random.random():
                current_seq = new_seq
                current_cost = new_cost

                if new_cost < best_cost:
                    best_seq = new_seq[:]
                    best_cost = new_cost

            temp *= cooling

            if i % 1000 == 0 and i > 0:
                if current_cost == best_cost and temp < 5.0:
                    current_seq = best_seq[:]
                    for _ in range(5):
                        a, b = random.sample(range(n), 2)
                        current_seq[a], current_seq[b] = current_seq[b], current_seq[a]
                    current_cost = workload.get_opt_seq_cost(current_seq)
                    temp = 30.0

        return best_seq, best_cost

    def adaptive_large_neighborhood_search(seq, base_cost):
        current_seq = seq[:]
        current_cost = base_cost
        best_seq = seq[:]
        best_cost = base_cost

        stagnation = 0
        iteration = 0

