                    best_c = float('inf')
                    for p in positions:
                        ts = new_seq[:p] + [txn] + new_seq[p:]
                        c = workload.get_opt_seq_cost(ts)
                        if c < best_c:
                            best_c = c
                            best_p = p
                    new_seq.insert(best_p, txn)

