            elapsed = (time.time() - start_time) / max_runtime
            temp = 50.0 * (1.0 - elapsed)

            if delta < 0:
                current_seq = new_seq
                current_cost = new_cost
                if new_cost < best_cost:
                    best_seq = new_seq[:]
                    best_cost = new_cost
                    stagnation = 0
                else:
                    stagnation += 1
            elif temp > 1e-3 and random.random() < math.exp(-delta / temp):
                current_seq = new_seq
                current_cost = new_cost
                stagnation += 1
            else:
                stagnation += 1

            if stagnation > 40:
